import{bV as a,aL as e,u as i,G as n}from"./chunks/framework.BfzMay2U.js";const u=JSON.parse('{"title":"windows 开发环境部署","description":"","frontmatter":{},"headers":[],"relativePath":"views/rust/windows-env-rust.md","filePath":"views/rust/windows-env-rust.md"}'),t={name:"views/rust/windows-env-rust.md"};function p(l,s,r,d,o,c){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="windows-开发环境部署" tabindex="-1">windows 开发环境部署 <a class="header-anchor" href="#windows-开发环境部署" aria-label="Permalink to &quot;windows 开发环境部署&quot;">​</a></h1><h2 id="下载" tabindex="-1">下载 <a class="header-anchor" href="#下载" aria-label="Permalink to &quot;下载&quot;">​</a></h2><p><a href="https://www.rust-lang.org/zh-CN/" target="_blank" rel="noreferrer">https://www.rust-lang.org/zh-CN/</a></p><p>找到<code>rustup-init.exe</code></p><p>需要一些<code>vc++</code>的一些库，如果你不想使用微软这些东西，可以使用<code>MSYS2</code></p><h3 id="msys2" tabindex="-1">MSYS2 <a class="header-anchor" href="#msys2" aria-label="Permalink to &quot;MSYS2&quot;">​</a></h3><blockquote><p>集成了<code>pacman</code>和<code>Mingw-w64</code>的<code>Cygwin</code>升级版，提供了<code>bash shell</code>等<code>linux</code>环境、版本控制软件<code>git/hg</code>和<code>MinGW-w64</code>工具链。</p></blockquote><ul><li><p>下载：<a href="https://www.msys2.org/" target="_blank" rel="noreferrer">https://www.msys2.org/</a></p></li><li><p>如果太慢，到这里：<a href="https://mirrors.tuna.tsinghua.edu.cn/msys2/distrib/x86_64/" target="_blank" rel="noreferrer">https://mirrors.tuna.tsinghua.edu.cn/msys2/distrib/x86_64/</a></p></li></ul><p>下载好之后进行解压，目录内容如下</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220913215323.png" alt="jieya" loading="lazy"></p><p>使用编辑器打开<code>msys2_shell.cmd</code></p><div class="language-cmd vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 找到 rem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> set </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MSYS2_PATH_TYPE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inherit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 去掉rem</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MSYS2_PATH_TYPE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inherit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>保存之后退出，双击它运行。</p><h2 id="创建比较合适的目录" tabindex="-1">创建比较合适的目录 <a class="header-anchor" href="#创建比较合适的目录" aria-label="Permalink to &quot;创建比较合适的目录&quot;">​</a></h2><p>比如在 D 盘创建一个<code>rust</code>目录，将下载好的<code>rustup-init.exe</code>可执行文件放到目录中，确保目录地址没有中文。</p><p>如果你不配置，默认会都安装到 C 盘，后面如果有些库会装的很大，所以尽可能的不要安装在 C 盘，可以在 D 盘里安装。</p><p>新建目录</p><ul><li><code>D:\\rust\\cargo</code></li><li><code>D:\\rust\\rustup</code></li></ul><p>和<code>rustup-init.exe</code>同级</p><h3 id="配置环境变量" tabindex="-1">配置环境变量 <a class="header-anchor" href="#配置环境变量" aria-label="Permalink to &quot;配置环境变量&quot;">​</a></h3><p>在环境变量里添加系统变量：</p><ol><li><p><code>CARGO_HOME</code>：<code>D:\\rust\\cargo</code></p></li><li><p><code>RUSTUP_HOME</code>：<code>D:\\rust\\rustup</code></p></li></ol><p>然后在<code>PATH</code>环境变量中加入：</p><p><code>%CARGO_HOME%\\bin;</code>前面原有的内容千万不能删掉，这是紧挨着后面添加的，一定要有分号进行分隔。</p><h3 id="设置中科大的源" tabindex="-1">设置中科大的源 <a class="header-anchor" href="#设置中科大的源" aria-label="Permalink to &quot;设置中科大的源&quot;">​</a></h3><p>再加入 2 个环境变量</p><ol><li><code>RUSTUP_DIST_SERVER</code>：<code>https://mirrors.ustc.edu.cn/rust-static</code></li><li><code>RUSTUP_UPDATE_ROOT</code>：<code>https://mirrors.ustc.edu.cn/rust-static/rustup</code></li></ol><h2 id="运行安装" tabindex="-1">运行安装 <a class="header-anchor" href="#运行安装" aria-label="Permalink to &quot;运行安装&quot;">​</a></h2><p>打开刚在打开的<code>msys2_shell.cmd</code>命令窗口，进入<code>d:\\rust</code>目录</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./rustup-init.exe</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>我们这里是不使用微软的那套的，所以不用介意出现的内容，继续输入<code>y</code>即可。</p><p>到了有选项的地方，会有一个默认的安装选项，所以我们需要改一下，如果你微软的相关的软件装好了，那就默认往下吧，这里我们不默认，需要修改，所以选 2</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220913220611.png" alt="" loading="lazy"></p><p>然后可以把上面选中的内容<code>copy</code>一份到下面进行修改输入内容为</p><p><code>x86_64-pc-windows-gnu</code>，这就是为啥要装<code>MSYS2</code>的原因，然后直接回车，直到出现：<code>Modify PATH variable?</code>，这里写<code>n</code>，不需要它帮我们设置环境变量 ，因为我们已经设置好了，然后出现下面的选项界面。</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220913220823.png" alt="" loading="lazy"></p><p>最后再按下回车，等他下载完成。</p><p>如果装成功，使用命令进行测试</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rustc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -V</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rustc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.40.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>会出现对应的版本</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -V</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.40.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rustup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -V</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rustup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.21.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,42)])])}const k=a(t,[["render",p]]);export{u as __pageData,k as default};
